import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Encode user input to prevent XSS
        String encodedName = Encode.forHtml(name);

        System.out.println("Hello, " + encodedName + "!");

        // Safe output without executing scripts
        System.out.println("&lt;script&gt;alert('XSS Attack!')&lt;/script&gt;");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
